# ── EMBEDDED LOGO IMAGE (base64) ──────────────────────────────
_LOGO_B64 = """

"""

def _extract_logo_to_temp():
    """Decode the embedded logo and write to a temp file for tk.PhotoImage."""
    data = base64.b64decode(_LOGO_B64.strip())
    tmp = tempfile.NamedTemporaryFile(suffix=".png", delete=False)
    tmp.write(data)
    tmp.close()
    return tmp.name

# Extract once at startup
_LOGO_TEMP_PATH = _extract_logo_to_temp()


