    def _load_logo(self):
        """Load the logo image once and store it for reuse across all screens."""
        if os.path.exists(_LOGO_TEMP_PATH):
            try:
                self.logo_photo = tk.PhotoImage(file=_LOGO_TEMP_PATH)
                # Scale down if image is too large (tk.PhotoImage subsample)
                # Subsample by 2 = half size, adjust as needed
                w = self.logo_photo.width()
                h = self.logo_photo.height()
                # Target header height ~120px wide ~580px
                factor = max(1, w // 580)
                if factor > 1:
                    self.logo_photo = self.logo_photo.subsample(factor, factor)
            except Exception as e:
                print("Logo load error:", e)
                self.logo_photo = None

