    def validate_digits(self, text_action):
        return text_action.isdigit() or text_action == ""

    def validate_scores(self, text_action):
        if text_action == "":
            return True
        try:
            val = float(text_action)
            return 0 <= val <= 100
        except ValueError:
            return False

    def parse_formatted_amount(self, text):
        clean_text = text.replace(",", "").strip()
        if not clean_text:
            return 0.0
        try:
            return float(clean_text)
        except ValueError:
            return 0.0

    def uppercase_entry_trace(self, var_name, index, mode, text_var, entry_widget):
        current_pos = entry_widget.index(tk.INSERT)
        value = text_var.get()
        text_var.set(value.upper())
        entry_widget.icursor(current_pos)

    def format_and_validate_reg_date(self, *args):
        value = self.reg_date_var.get()
        digits = "".join([c for c in value if c.isdigit()])
        digits = digits[:6]
        formatted = ""
        if len(digits) > 0:
            day = int(digits[:2])
            if day > 31: digits = "31" + digits[2:]
            elif day == 0 and len(digits) >= 2: digits = "01" + digits[2:]
            formatted += digits[:2]
        if len(digits) > 2:
            month = int(digits[2:4])
            if month > 12: digits = digits[:2] + "12" + digits[4:]
            elif month == 0 and len(digits) >= 4: digits = digits[:2] + "01" + digits[4:]
            formatted += "/" + digits[2:4]
        if len(digits) > 4:
            formatted += "/" + digits[4:6]
        self.reg_date_var.trace_remove("write", self.reg_date_trace_id)
        self.reg_date_var.set(formatted)
        self.reg_date_trace_id = self.reg_date_var.trace_add("write", self.format_and_validate_reg_date)

    def format_and_validate_dob(self, *args):
        value = self.dob_var.get()
        digits = "".join([c for c in value if c.isdigit()])
        digits = digits[:8]
        formatted = ""
        if len(digits) > 0:
            month = int(digits[:2])
            if month > 12: digits = "12" + digits[2:]
            elif month == 0 and len(digits) >= 2: digits = "01" + digits[2:]
            formatted += digits[:2]
        if len(digits) > 2:
            day = int(digits[2:4])
            if day > 31: digits = digits[:2] + "31" + digits[4:]
            elif day == 0 and len(digits) >= 4: digits = digits[:2] + "01" + digits[4:]
            formatted += "/" + digits[2:4]
        if len(digits) > 4:
            formatted += "/" + digits[4:8]
        self.dob_var.trace_remove("write", self.dob_trace_id)
        self.dob_var.set(formatted)
        self.dob_trace_id = self.dob_var.trace_add("write", self.format_and_validate_dob)

