    def verify_student_login(self):
        student_id = self.student_id_entry.get().strip()
        if not student_id:
            messagebox.showerror("Error", "Please input a valid Student ID.")
            return
        if student_id in student_database:
            self.show_student_dashboard(student_id)
        else:
            messagebox.showerror("Not Found", "No profile records found for this student ID.")

    @staticmethod
    def _numeric_to_letter_grade(numeric_str):
        try:
            score = float(numeric_str)
            if 70 <= score <= 100: return "A"
            elif 60 <= score < 70: return "B"
            elif 50 <= score < 60: return "C"
            elif 40 <= score < 50: return "D"
            else:                  return "F"
        except (ValueError, TypeError):
            return numeric_str

    def show_student_dashboard(self, student_id):
        self.clear_window()
