        has_incomplete_fees_block = data.get("fees_incomplete_block", False)

        wrapper = tk.Frame(self.root, bg="black", padx=15, pady=5)
        wrapper.pack(fill="both", expand=True)

        self.add_university_header(wrapper)
        tk.Label(wrapper, text=f"Welcome back, {data['first_name']} {data['surname']}",
                 font=self.font_title, bg="black", fg="#28a745").pack(pady=2)

        student_notebook = ttk.Notebook(wrapper)
        student_notebook.pack(fill="both", expand=True, pady=10)

        s_tab1 = tk.Frame(student_notebook, bg="black", padx=10, pady=10)
        s_tab2 = tk.Frame(student_notebook, bg="black", padx=10, pady=10)
        s_tab3 = tk.Frame(student_notebook, bg="black", padx=10, pady=10)

        student_notebook.add(s_tab1, text=" Personal Profile ")
        student_notebook.add(s_tab2, text=" Module Assessments ")
        student_notebook.add(s_tab3, text=" Financial Status ")

        details = [
            ("First Name:", data['first_name']),
            ("Surname:", data['surname']),
            ("Gender:", data['gender']),
            ("Date of Birth:", data['dob']),
            ("Phone Number:", data['phone']),
            ("Email Address:", data['email']),
            ("Home Address:", data['address'])
        ]
        for i, (lbl, val) in enumerate(details):
            tk.Label(s_tab1, text=lbl, font=self.font_label, bg="black", fg="#28a745").grid(
                row=i, column=0, sticky="w", pady=6)
            tk.Label(s_tab1, text=val, font=self.font_input, bg="black", fg="white").grid(
                row=i, column=1, sticky="w", padx=15, pady=6)

        tk.Label(s_tab2, text=f"Faculty: {data['faculty']} | Course: {data['course']}",
                 font=self.font_label, bg="black", fg="#ffc107").pack(pady=5)

        results_outer = tk.Frame(s_tab2, bg="black")
        results_outer.pack(fill="both", expand=True)

        results_frame = tk.LabelFrame(results_outer, text=" Recorded Grades Matrix ",
                                      font=self.font_label, bg="#111111", fg="white",
                                      padx=10, pady=10)
        results_frame.pack(fill="both", expand=True, pady=10)

        modules_display_map = {
            "ent_adm_math":        "COMPUTERIZED MATH",
            "ent_adm_comm":        "DATA COMMUNICATION",
            "ent_adm_database":    "DATA BASE",
            "ent_adm_struct_prog": "STRUCTURED PROGRAMMING",
            "ent_adm_soft_eng":    "SOFTWARE ENGINEERING",
            "ent_adm_comp_hw":     "COMPUTER HARDWARE"
        }

        for idx, (key, label) in enumerate(modules_display_map.items()):
            raw_score = data["grades"].get(key, "") or ""
            approved_score = raw_score

            for sub in pending_grades_queue.values():
                if sub["student_id"] == student_id and sub["module_key"] == key:
                    if sub["status"] == "APPROVED":
                        approved_score = sub["grade"]
                    elif sub["status"] in ("PENDING", "REJECTED"):
                        approved_score = "Pending"

            if approved_score and approved_score != "Pending":
                display_val = self._numeric_to_letter_grade(approved_score)
            else:
                display_val = "Pending"

            grade_colour = {"A": "#28a745", "B": "#17a2b8",
                            "C": "#ffc107", "D": "#fd7e14", "F": "#dc3545"}.get(display_val, "white")

            if has_incomplete_fees_block and display_val not in ("Pending",):
                display_label_val = "* * *"
                grade_colour = "#555555"
            else:
                display_label_val = display_val

            tk.Label(results_frame, text=label + ":", font=self.font_label,
                     bg="#111111", fg="#cccccc").grid(row=idx, column=0, sticky="w", pady=4)
            tk.Label(results_frame, text=display_label_val, font=self.font_title,
                     bg="#111111", fg=grade_colour).grid(row=idx, column=1, sticky="w", padx=20, pady=4)

        if has_incomplete_fees_block:
            overlay = tk.Frame(results_outer, bg="#1a0000", bd=2, relief="ridge")
            overlay.place(relx=0, rely=0, relwidth=1, relheight=1)
            tk.Label(overlay, text="", bg="#1a0000").pack(expand=True)
            warning_frame = tk.Frame(overlay, bg="#3d0000", bd=3, relief="solid")
            warning_frame.place(relx=0.05, rely=0.15, relwidth=0.9, relheight=0.7)
            tk.Label(warning_frame, text="⚠", font=("Tahoma", 36, "bold"),
                     bg="#3d0000", fg="#ff4444").pack(pady=(20, 5))
            tk.Label(warning_frame, text="INCOMPLETE FEES", font=("Tahoma", 18, "bold"),
                     bg="#3d0000", fg="#ff2222").pack(pady=2)
            tk.Label(warning_frame, text="Your grade results are locked.",
                     font=("Tahoma", 11, "bold"), bg="#3d0000", fg="#ffaaaa").pack(pady=4)
            tk.Label(warning_frame,
                     text="Please clear your outstanding balance\nwith the Finance Office to unlock\nyour academic results.",
                     font=("Tahoma", 10), bg="#3d0000", fg="#ff8888", justify="center").pack(pady=6)
            bal = data.get("balance", "N/A")
            tk.Label(warning_frame, text=f"Outstanding Balance:  Le {bal}",
                     font=("Tahoma", 12, "bold"), bg="#3d0000", fg="#ffc107").pack(pady=(6, 14))

        tk.Label(s_tab3, text=f"Total Structured Fees: Le {data['total_fees']}",
                 font=self.font_label, bg="black", fg="white").pack(anchor="w", pady=4)
        tk.Label(s_tab3, text=f"Ledger Paid: Le {data['amount_paid']}",
                 font=self.font_label, bg="black", fg="#28a745").pack(anchor="w", pady=4)
        tk.Label(s_tab3, text=f"Outstanding Balance: Le {data['balance']}",
                 font=self.font_title, bg="black", fg="#dc3545").pack(anchor="w", pady=6)

        btn_logout = ttk.Button(wrapper, text="Logout of Portal", style="Red.TButton",
                                width=18, command=self.show_role_selection_screen)
        btn_logout.pack(side="bottom", pady=10)

