    def update_admin_course_dropdown(self, event):
        fac = self.cb_admin_faculty.get()
        if fac in FACULTY_COURSES:
            self.cb_admin_course.config(values=FACULTY_COURSES[fac])
            self.cb_admin_course.set("")

    def update_module_visibility(self, event=None):
        faculty = self.cb_admin_faculty.get()
        course = self.cb_admin_course.get()
        semester = self.cb_admin_semester.get()

        for label_widget, entry_widget in getattr(self, "module_widgets", []):
            label_widget.grid_remove()
            entry_widget.grid_remove()
            entry_widget.config(state="normal")
            entry_widget.delete(0, tk.END)
            entry_widget.config(state="disabled")

        if faculty == "FICT" and course == "BBIT":
            if semester == "1":
                modules = ["French Language", "Creative Innovation",
                           "Introduction to Communication Skills",
                           "Programming", "Civic", "Computer Skills"]
            elif semester == "2":
                modules = ["Computerized Math", "Data Communication", "Data Base",
                           "Introduction to Computer Hardware",
                           "Software Engineering", "Structured Programming"]
            else:
                return
            for i, (label_widget, entry_widget) in enumerate(self.module_widgets):
                if i < len(modules):
                    label_widget.config(text=modules[i] + ":")
                    label_widget.grid()
                    entry_widget.grid()

