    def process_admin_payment_trigger(self):
        amt = self.parse_formatted_amount(self.ent_pay_trigger.get())
        if amt <= 0:
            messagebox.showerror("Error", "Please input a transaction amount higher than 0.")
            return
        total = self.parse_formatted_amount(self.ent_admin_total_fees.get())
        current_paid = self.parse_formatted_amount(self.ent_admin_paid.get()) + amt
        rem_balance = total - current_paid
        self.ent_admin_paid.config(state="normal")
        self.ent_admin_paid.delete(0, tk.END)
        self.ent_admin_paid.insert(0, f"{current_paid:,.2f}")
        self.ent_admin_paid.config(state="readonly")
        self.ent_admin_balance.config(state="normal")
        self.ent_admin_balance.delete(0, tk.END)
        self.ent_admin_balance.insert(0, f"{rem_balance:,.2f}")
        self.ent_admin_balance.config(state="readonly")
        self.print_live_transaction_receipt("INSTANT DIRECT DEBIT", amt, rem_balance)
        self.ent_pay_trigger.delete(0, tk.END)

    def _continue_payment_load_student(self):
        sid = self.ent_cont_student_id.get().strip()
        if not sid:
            messagebox.showerror("Input Error", "Please enter a Student ID.")
            return
        data = student_database.get(sid)
        if not data:
            self.cont_pay_info_var.set("❌  Student not found. Register them via Personal Details first.")
            return
        name = f"{data.get('first_name','N/A')} {data.get('surname','N/A')}"
        total   = data.get('total_fees', '0.00')
        paid    = data.get('amount_paid', '0.00')
        balance = data.get('balance', '0.00')
        self.cont_pay_info_var.set(
            f"Student:  {name}  ({sid})\n"
            f"Total Fees:  Le {total}    |    Paid:  Le {paid}    |    Balance:  Le {balance}")
        self._cont_pay_student_id = sid

    def _continue_payment_process(self):
        sid = getattr(self, "_cont_pay_student_id", None)
        if not sid or sid not in student_database:
            messagebox.showerror("No Student Loaded",
                                 "Please load a student first using 'Load Student'.")
            return
        amt_str = self.ent_cont_pay_amount.get().strip()
        try:
            amt = float(amt_str.replace(",", ""))
            if amt <= 0:
                raise ValueError
        except (ValueError, TypeError):
            messagebox.showerror("Invalid Amount",
                                 "Please enter a valid payment amount greater than 0.")
            return
        data = student_database[sid]
        current_paid = self.parse_formatted_amount(data.get("amount_paid", "0.00"))
        total        = self.parse_formatted_amount(data.get("total_fees",  "0.00"))
        new_paid     = current_paid + amt
        new_balance  = total - new_paid
        data["amount_paid"] = f"{new_paid:,.2f}"
        data["balance"]     = f"{new_balance:,.2f}"
        name = f"{data.get('first_name','N/A')} {data.get('surname','N/A')}"
        self.cont_pay_info_var.set(
            f"Student:  {name}  ({sid})\n"
            f"Total Fees:  Le {data['total_fees']}    |    Paid:  Le {data['amount_paid']}"
            f"    |    Balance:  Le {data['balance']}")
        self.print_live_transaction_receipt("CONTINUE PAYMENT", amt, new_balance)
        self.ent_cont_pay_amount.delete(0, tk.END)
        messagebox.showinfo("Payment Posted",
                            f"Payment of Le {amt:,.2f} posted for {name}.\n"
                            f"New Balance:  Le {new_balance:,.2f}")

