    def verify_administrative_login(self):
        if self.pwd_entry.get() == "admin123":
            self.show_administrative_dashboard()
        else:
            messagebox.showerror("Access Denied", "Incorrect password!")

    def toggle_password_visibility(self):
        if self.pwd_entry.cget("show") == "*":
            self.pwd_entry.config(show="")
            self.btn_toggle_pwd.config(text="Hide")
        else:
            self.pwd_entry.config(show="*")
            self.btn_toggle_pwd.config(text="Show")

