    def _build_admin_approvals_tab(self):
        t4 = self.tab_approvals
        tk.Label(t4, text="Lecturer Grade Submission Queue",
                 font=self.font_title, bg="black", fg="#ffc107").pack(pady=(5, 2))
        tk.Label(t4, text="Review and approve or reject grades submitted by lecturers.",
                 font=("Tahoma", 9), bg="black", fg="#aaaaaa").pack(pady=(0, 5))

        search_row = tk.Frame(t4, bg="black")
        search_row.pack(fill="x", padx=5, pady=(0, 6))
        tk.Label(search_row, text="Search by Student ID:", font=self.font_label,
                 bg="black", fg="white").pack(side="left", padx=(0, 6))
        tk.Label(search_row, text="90500", font=("Tahoma", 10, "bold"),
                 bg="#1a1a1a", fg="#aaaaaa", relief="flat", padx=4).pack(side="left")
        self.approval_search_var = tk.StringVar()
        search_entry = tk.Entry(search_row, textvariable=self.approval_search_var,
                                font=self.font_input, width=6, bg="#222222",
                                fg="white", insertbackground="white",
                                validate="key", validatecommand=(self.val_digits_only, '%P'))
        search_entry.pack(side="left", padx=(0, 6))
        ttk.Button(search_row, text="🔍 Search", style="Blue.TButton",
                   command=self._approval_search_by_student).pack(side="left", padx=4)
        ttk.Button(search_row, text="✕ Clear", style="Yellow.TButton",
                   command=self._approval_clear_search).pack(side="left", padx=4)

        cols = ("Sub ID", "Student ID", "Module", "Lecturer", "Grade", "Status", "Submitted")
        self.approval_tree = ttk.Treeview(t4, columns=cols, show="headings", height=7)
        col_widths = [55, 80, 150, 160, 55, 70, 130]
        for col, w in zip(cols, col_widths):
            self.approval_tree.heading(col, text=col)
            self.approval_tree.column(col, width=w, anchor="center")
        self.approval_tree.pack(fill="both", expand=True, padx=5)

        self.approval_tree.tag_configure("PENDING",  background="#333300", foreground="#ffc107")
        self.approval_tree.tag_configure("APPROVED", background="#003300", foreground="#28a745")
        self.approval_tree.tag_configure("REJECTED", background="#330000", foreground="#dc3545")
        self.approval_tree.tag_configure("APPROVED_INCOMPLETE",
                                          background="#1a1a00", foreground="#ff8c00")

        btn_row = tk.Frame(t4, bg="black")
        btn_row.pack(pady=8)
        self._build_approve_dropdown_btn(btn_row)
        ttk.Button(btn_row, text="👤 View Profile", style="Blue.TButton",
                   command=self._admin_view_student_profile).pack(side="left", padx=5)
        ttk.Button(btn_row, text="✖ Reject Selected", style="Red.TButton",
                   command=self._admin_reject_grade).pack(side="left", padx=5)
        ttk.Button(btn_row, text="↺ Refresh Queue", style="Yellow.TButton",
                   command=self._refresh_approvals_tree).pack(side="left", padx=5)
        self._refresh_approvals_tree()

    def _build_approve_dropdown_btn(self, parent):
        container = tk.Frame(parent, bg="black")
        container.pack(side="left", padx=5)
        main_btn = ttk.Button(container, text="✔ Approve Selected",
                              style="Green.TButton",
                              command=lambda: self._admin_approve_grade("APPROVED"))
        main_btn.pack(side="left")
        arrow_btn = tk.Button(container, text="▼", font=("Tahoma", 8, "bold"),
                              bg="#218838", fg="white", bd=0, padx=4,
                              cursor="hand2",
                              command=lambda: self._show_approve_menu(arrow_btn))
        arrow_btn.pack(side="left", padx=(1, 0))
        self._approve_arrow_btn = arrow_btn

    def _show_approve_menu(self, anchor_widget):
        menu = tk.Menu(self.root, tearoff=0, bg="#222222", fg="white",
                       font=("Tahoma", 10), activebackground="#444444",
                       activeforeground="white", relief="flat")
        menu.add_command(label="✔  Approved  (Full Access)",
                         command=lambda: self._admin_approve_grade("APPROVED"))
        menu.add_separator()
        menu.add_command(label="⚠  Approved — Incomplete Fees  (Grades Locked)",
                         command=lambda: self._admin_approve_grade("APPROVED_INCOMPLETE"))
        x = anchor_widget.winfo_rootx()
        y = anchor_widget.winfo_rooty() + anchor_widget.winfo_height()
        menu.tk_popup(x, y)

    def _refresh_approvals_tree(self, filter_id=None):
        for row in self.approval_tree.get_children():
            self.approval_tree.delete(row)
        for sub_id, sub in pending_grades_queue.items():
            if filter_id and sub["student_id"] != filter_id:
                continue
            self.approval_tree.insert("", "end", iid=sub_id,
                                      tags=(sub["status"],),
                                      values=(sub_id, sub["student_id"],
                                              sub["module_label"], sub["lecturer_name"],
                                              sub["grade"], sub["status"], sub["submitted_at"]))

    def _approval_search_by_student(self):
        suffix = self.approval_search_var.get().strip()
        if not suffix:
            messagebox.showwarning("Input Required",
                                   "Please enter the last digits of the Student ID to search.")
            return
        full_id = STUDENT_ID_PREFIX + suffix
        matches = [s for s in pending_grades_queue.values() if s["student_id"] == full_id]
        if not matches:
            messagebox.showinfo("No Records",
                                f"No grade submissions found for Student ID: {full_id}")
            return
        self._refresh_approvals_tree(filter_id=full_id)

    def _approval_clear_search(self):
        self.approval_search_var.set("")
        self._refresh_approvals_tree()

