    def _admin_approve_grade(self, approval_type="APPROVED"):
        selected = self.approval_tree.selection()
        if not selected:
            messagebox.showwarning("No Selection", "Please select a submission to approve.")
            return
        sub_id = selected[0]
        sub = pending_grades_queue.get(sub_id)
        if not sub:
            return
        current_status = sub["status"]
        if current_status == "APPROVED" and approval_type == "APPROVED":
            messagebox.showinfo("Already Approved", "This submission is already fully APPROVED.")
            return
        if current_status == "REJECTED":
            messagebox.showinfo("Already Rejected", "This submission has been REJECTED and cannot be re-approved.")
            return
        if current_status not in ("PENDING", "APPROVED_INCOMPLETE"):
            messagebox.showinfo("Cannot Process", f"This submission has status '{current_status}' and cannot be changed.")
            return
        if current_status == "APPROVED_INCOMPLETE" and approval_type == "APPROVED":
            confirm = messagebox.askyesno("Confirm Full Access",
                f"Upgrade Student {sub['student_id']} to FULL ACCESS?\n\n"
                "This will remove the fee lock and allow the student\n"
                "to see their grades immediately.\n\nProceed?")
            if not confirm:
                return
        sub["status"] = approval_type
        sid = sub["student_id"]
        if sid in student_database:
            student_database[sid]["grades"][sub["module_key"]] = sub["grade"]
            if approval_type == "APPROVED_INCOMPLETE":
                student_database[sid]["fees_incomplete_block"] = True
            else:
                student_database[sid]["fees_incomplete_block"] = False
        entry_widget = getattr(self, sub["module_key"], None)
        if entry_widget:
            entry_widget.config(state="normal")
            entry_widget.delete(0, tk.END)
            entry_widget.insert(0, sub["grade"])
            entry_widget.config(state="disabled")
        self._refresh_approvals_tree()
        if approval_type == "APPROVED":
            messagebox.showinfo("Approved — Full Access",
                                f"Grade for {sub['student_id']} | {sub['module_label']} has been APPROVED.")
        else:
            messagebox.showinfo("Approved — Incomplete Fees",
                                f"Grade for {sub['student_id']} | {sub['module_label']} approved but grades LOCKED until fees cleared.")

    def _admin_reject_grade(self):
        selected = self.approval_tree.selection()
        if not selected:
            messagebox.showwarning("No Selection", "Please select a submission to reject.")
            return
        sub_id = selected[0]
        sub = pending_grades_queue.get(sub_id)
        if not sub:
            return
        if sub["status"] != "PENDING":
            messagebox.showinfo("Already Processed", f"This submission is already {sub['status']}.")
            return
        sub["status"] = "REJECTED"
        self._refresh_approvals_tree()
        messagebox.showinfo("Rejected",
                            f"Grade submission for {sub['student_id']} | {sub['module_label']} has been REJECTED.")

