    def _lecturer_search_student(self, module_label, module_key, lecturer_name):
        suffix = self.lect_student_suffix.get().strip()
        if not suffix:
            messagebox.showerror("Input Error", "Please enter the last digits of the Student ID.")
            return
        full_id = STUDENT_ID_PREFIX + suffix
        if full_id not in student_database:
            messagebox.showerror("Not Found",
                                 f"No student record found for ID: {full_id}\n"
                                 "Please ask admin to register the student first.")
            for var in self.lect_info_vars.values():
                var.set("—")
            self._lect_current_student_id = None
            self.lect_grade_entry.config(state="disabled")
            self.lect_submit_btn.config(state="disabled")
            return
        data = student_database[full_id]
        self._lect_current_student_id = full_id
        self.lect_info_vars["Full Name"].set(f"{data.get('first_name', 'N/A')} {data.get('surname', 'N/A')}")
        self.lect_info_vars["Programme"].set(f"{data.get('faculty', 'N/A')} — {data.get('course', 'N/A')}")
        self.lect_info_vars["Semester"].set(f"Semester {data.get('semester', 'N/A')} | {data.get('academic_year', 'N/A')}")
        self.lect_status_var.set("")
        self.lect_grade_entry.config(state="normal")
        self.lect_grade_entry.delete(0, tk.END)
        for sub in pending_grades_queue.values():
            if sub["student_id"] == full_id and sub["module_key"] == module_key:
                if sub["status"] == "PENDING":
                    self.lect_status_var.set("⚠ Grade already submitted for this student in this module (PENDING).")
                    self.lect_grade_entry.config(state="disabled")
                    self.lect_submit_btn.config(state="disabled")
                    return
                elif sub["status"] == "APPROVED":
                    self.lect_status_var.set("✔ Grade already submitted for this student in this module (APPROVED).")
                    self.lect_grade_entry.config(state="disabled")
                    self.lect_submit_btn.config(state="disabled")
                    return
        self.lect_grade_entry.config(state="normal")
        self.lect_submit_btn.config(state="normal")

    def _lecturer_submit_grade(self, module_label, module_key, lecturer_name):
        if not self._lect_current_student_id:
            messagebox.showerror("No Student", "Please search and load a student record first.")
            return
        grade = self.lect_grade_entry.get().strip()
        if not grade:
            messagebox.showerror("Input Error", "Please enter a grade before submitting.")
            return
        try:
            g_val = float(grade)
            if not (0 <= g_val <= 100):
                raise ValueError
        except ValueError:
            messagebox.showerror("Invalid Grade", "Grade must be a number between 0 and 100.")
            return
        for sub in pending_grades_queue.values():
            if (sub["student_id"] == self._lect_current_student_id and sub["module_key"] == module_key):
                if sub["status"] == "PENDING":
                    messagebox.showwarning("Already Submitted",
                                           "Grade already submitted. Status: PENDING — awaiting Admin approval.")
                    self.lect_grade_entry.config(state="disabled")
                    self.lect_submit_btn.config(state="disabled")
                    return
                elif sub["status"] == "APPROVED":
                    messagebox.showwarning("Already Approved",
                                           "Grade already submitted. Status: APPROVED — grade has been finalised.")
                    self.lect_grade_entry.config(state="disabled")
                    self.lect_submit_btn.config(state="disabled")
                    return
        _submission_counter[0] += 1
        sub_id = f"SUB{_submission_counter[0]:04d}"
        pending_grades_queue[sub_id] = {
            "student_id":    self._lect_current_student_id,
            "module_key":    module_key,
            "module_label":  module_label,
            "lecturer_name": lecturer_name,
            "grade":         grade,
            "status":        "PENDING",
            "submitted_at":  datetime.now().strftime("%d/%m/%Y %H:%M")
        }
        self.lect_grade_entry.config(state="disabled")
        self.lect_submit_btn.config(state="disabled")
        self.lect_status_var.set(f"✔ Grade submitted as PENDING (Ref: {sub_id}). Awaiting Admin approval.")
        messagebox.showinfo("Submitted",
                            f"Grade submitted successfully!\n\n"
                            f"Reference:  {sub_id}\n"
                            f"Student:    {self._lect_current_student_id}\n"
                            f"Module:     {module_label}\n"
                            f"Grade:      {grade}\n"
                            f"Status:     PENDING\n\n"
                            "The Admin must approve before the student can see this grade.")


